import{_ as a,o as e,c as l,ag as r}from"./chunks/framework.DXGyWiRo.js";const c=JSON.parse('{"title":"B夫人（Rose Blumkin）","description":"","frontmatter":{},"headers":[],"relativePath":"04_people/B夫人.md","filePath":"04_people/B夫人.md"}'),d={name:"04_people/B夫人.md"};function i(o,t,h,n,u,s){return e(),l("div",null,[...t[0]||(t[0]=[r('<h1 id="b夫人-rose-blumkin" tabindex="-1">B夫人（Rose Blumkin） <a class="header-anchor" href="#b夫人-rose-blumkin" aria-label="Permalink to &quot;B夫人（Rose Blumkin）&quot;">​</a></h1><h2 id="基本信息" tabindex="-1">基本信息 <a class="header-anchor" href="#基本信息" aria-label="Permalink to &quot;基本信息&quot;">​</a></h2><table tabindex="0"><thead><tr><th>属性</th><th>内容</th></tr></thead><tbody><tr><td>全名</td><td>Rose Blumkin</td></tr><tr><td>昵称</td><td>Mrs. B（B夫人）</td></tr><tr><td>出生</td><td>1893年，俄国</td></tr><tr><td>逝世</td><td>1997年（104岁）</td></tr><tr><td>职业</td><td>企业家</td></tr><tr><td>公司</td><td><a href="./../03_公司库/内布拉斯加家具城.html">内布拉斯加家具城</a></td></tr></tbody></table><h2 id="人生传奇" tabindex="-1">人生传奇 <a class="header-anchor" href="#人生传奇" aria-label="Permalink to &quot;人生传奇&quot;">​</a></h2><h3 id="早年" tabindex="-1">早年 <a class="header-anchor" href="#早年" aria-label="Permalink to &quot;早年&quot;">​</a></h3><ul><li>1893年生于俄国，<strong>未受过一天正式教育</strong></li><li>1917年移民美国</li><li>1937年用<strong>500美元</strong>创办家具店</li></ul><h3 id="创业故事" tabindex="-1">创业故事 <a class="header-anchor" href="#创业故事" aria-label="Permalink to &quot;创业故事&quot;">​</a></h3><ul><li>从摆地摊开始，逐步做大</li><li>格言：<strong>&quot;低价卖，说实话&quot;</strong></li><li>一周七天工作，从开门待到关门</li></ul><h3 id="高龄传奇" tabindex="-1">高龄传奇 <a class="header-anchor" href="#高龄传奇" aria-label="Permalink to &quot;高龄传奇&quot;">​</a></h3><table tabindex="0"><thead><tr><th>年龄</th><th>事迹</th></tr></thead><tbody><tr><td>1983年</td><td>90岁，一周七天在卖场，卖给巴菲特公司</td></tr><tr><td>1984年</td><td>91岁，获纽约大学商业科学荣誉博士</td></tr><tr><td>1986年</td><td>93岁，仍在卖场工作</td></tr><tr><td>1987年</td><td>94岁，一周七天上班</td></tr><tr><td>1989年</td><td>96岁，因管理分歧短暂离开创办新店</td></tr><tr><td>1992年</td><td>99岁，回归NFM</td></tr><tr><td>1997年</td><td>104岁去世</td></tr></tbody></table><h2 id="管理风格" tabindex="-1">管理风格 <a class="header-anchor" href="#管理风格" aria-label="Permalink to &quot;管理风格&quot;">​</a></h2><h3 id="核心原则" tabindex="-1">核心原则 <a class="header-anchor" href="#核心原则" aria-label="Permalink to &quot;核心原则&quot;">​</a></h3><ol><li><strong>低价策略</strong>：薄利多销，击败所有竞争对手</li><li><strong>诚实经营</strong>：对顾客从不撒谎</li><li><strong>极致勤奋</strong>：一周七天，从早到晚</li><li><strong>家族传承</strong>：培养子女接班</li></ol><h3 id="运营效率" tabindex="-1">运营效率 <a class="header-anchor" href="#运营效率" aria-label="Permalink to &quot;运营效率&quot;">​</a></h3><ul><li>运营费用率仅<strong>16.5%</strong>（行业标杆35.6%）</li><li>单店年销售额超<strong>1亿美元</strong></li><li>超过奥马哈所有竞争对手总和</li></ul><h2 id="巴菲特评价" tabindex="-1">巴菲特评价 <a class="header-anchor" href="#巴菲特评价" aria-label="Permalink to &quot;巴菲特评价&quot;">​</a></h2><h3 id="经典语录" tabindex="-1">经典语录 <a class="header-anchor" href="#经典语录" aria-label="Permalink to &quot;经典语录&quot;">​</a></h3><blockquote><p>&quot;我宁愿和灰熊摔跤，也不愿和B夫人竞争。&quot; —— 1984年股东信</p></blockquote><blockquote><p>&quot;这个女人用500美元开始，现在每年卖1亿美元家具，从来没受过一天正式教育。&quot; —— 1984年股东信</p></blockquote><blockquote><p>&quot;每周七天，她从开门待到关门。我见过她以比竞争对手低5美元的价格卖出一块4,000美元的地毯。&quot; —— 1984年股东信</p></blockquote><h3 id="收购决策" tabindex="-1">收购决策 <a class="header-anchor" href="#收购决策" aria-label="Permalink to &quot;收购决策&quot;">​</a></h3><ul><li>无审计、无库存盘点、无资产核实</li><li>完全信任B夫人</li><li>90%股权，家族保留10%</li></ul><h2 id="家族传承" tabindex="-1">家族传承 <a class="header-anchor" href="#家族传承" aria-label="Permalink to &quot;家族传承&quot;">​</a></h2><table tabindex="0"><thead><tr><th>成员</th><th>关系</th><th>角色</th></tr></thead><tbody><tr><td>Louie Blumkin</td><td>儿子</td><td>总裁，全美最精明采购员</td></tr><tr><td>Ron Blumkin</td><td>孙子</td><td>管理层</td></tr><tr><td>Irv Blumkin</td><td>孙子</td><td>管理层</td></tr><tr><td>Steve Blumkin</td><td>孙子</td><td>管理层</td></tr></tbody></table><h2 id="影响" tabindex="-1">影响 <a class="header-anchor" href="#影响" aria-label="Permalink to &quot;影响&quot;">​</a></h2><h3 id="对伯克希尔" tabindex="-1">对伯克希尔 <a class="header-anchor" href="#对伯克希尔" aria-label="Permalink to &quot;对伯克希尔&quot;">​</a></h3><ul><li>树立了收购家族企业的典范</li><li>验证了&quot;买入优秀企业，让优秀经理人继续管&quot;的理念</li><li>提供了源源不断的现金用于其他投资</li></ul><h3 id="对商业教育" tabindex="-1">对商业教育 <a class="header-anchor" href="#对商业教育" aria-label="Permalink to &quot;对商业教育&quot;">​</a></h3><ul><li>巴菲特建议商学院把NFM作为案例研究</li><li>展示了低成本运营的极致效率</li><li>证明了创业者精神超越学历</li></ul><h2 id="在股东信中的年份" tabindex="-1">在股东信中的年份 <a class="header-anchor" href="#在股东信中的年份" aria-label="Permalink to &quot;在股东信中的年份&quot;">​</a></h2><p>1983, 1984, 1985, 1986, 1987</p><h2 id="相关链接" tabindex="-1">相关链接 <a class="header-anchor" href="#相关链接" aria-label="Permalink to &quot;相关链接&quot;">​</a></h2><ul><li><a href="./../03_公司库/内布拉斯加家具城.html">内布拉斯加家具城</a> - 创办的企业</li><li><a href="./../03_公司库/喜诗糖果.html">喜诗糖果</a> - 同为传奇子公司</li><li><a href="./Chuck_Huggins.html">Chuck Huggins</a> - 同为传奇经理人</li></ul><hr><p><em>最后更新：2026-04-09</em></p>',35)])])}const q=a(d,[["render",i]]);export{c as __pageData,q as default};
